    # Runtime UI helpers added outside Qt Designer.
    def _configure_responsive_ui(self):
        self._ui_scale = 1.0
        self._ui_scale_applied = False
        self.setMinimumSize(1360, 808)
        self.centralwidget.setMinimumSize(0, 0)
        self.tabWidget.setMinimumSize(0, 0)
        self.tabWidget.setDocumentMode(False)
        self.tabWidget.setIconSize(QtCore.QSize(18, 18))
        self.tabWidget.tabBar().setUsesScrollButtons(True)
        self.tabWidget.currentChanged.connect(self._apply_tab_accent)

        self.gridLayout_2.setContentsMargins(8, 8, 8, 8)
        self.gridLayout_2.setSpacing(0)

        self._responsive_labels = []
        self._normalise_font_sizes()
        self._layout_parameter_page()
        self._layout_visualize_page()
        self._layout_about_page()
        self._configure_scrollable_text()
        self._configure_numeric_inputs()
        self._configure_progress_bar()
        self._refresh_about_text()
        self._clear_designer_styles()
        self._apply_modern_styles()
        self._apply_direct_widget_styles()
        self._apply_tab_accent(self.tabWidget.currentIndex())
        self._apply_responsive_scale()

    def _normalise_font_sizes(self):
        self.setFont(QtGui.QFont("Segoe UI", 9))

        for widget in self.findChildren(QtWidgets.QWidget):
            font = widget.font()
            point_size = font.pointSize()
            if point_size > 12:
                font.setPointSize(12)
            if isinstance(widget, QtWidgets.QAbstractButton):
                font.setUnderline(False)
            widget.setFont(font)

    def _new_field_label(self, text, minimum_width=0):
        label = QtWidgets.QLabel(text)
        label.setTextFormat(QtCore.Qt.RichText)
        label.setAlignment(QtCore.Qt.AlignRight | QtCore.Qt.AlignVCenter)
        if minimum_width:
            label.setMinimumWidth(minimum_width)
        label.setMinimumHeight(30)
        label.setSizePolicy(QtWidgets.QSizePolicy.Minimum, QtWidgets.QSizePolicy.Fixed)
        font = label.font()
        font.setPointSize(11)
        font.setBold(True)
        label.setFont(font)
        self._responsive_labels.append(label)
        return label

    def _new_unit_label(self, text):
        label = QtWidgets.QLabel(text)
        label.setAlignment(QtCore.Qt.AlignLeft | QtCore.Qt.AlignVCenter)
        label.setMinimumWidth(28)
        label.setSizePolicy(QtWidgets.QSizePolicy.Minimum, QtWidgets.QSizePolicy.Fixed)
        font = label.font()
        font.setPointSize(10)
        label.setFont(font)
        self._responsive_labels.append(label)
        return label

    def _compact_line_edit(self, line_edit, minimum_width=70):
        line_edit.setMinimumSize(QtCore.QSize(minimum_width, 28))
        line_edit.setSizePolicy(QtWidgets.QSizePolicy.Preferred, QtWidgets.QSizePolicy.Fixed)

    def _add_parameter_field(self, layout, row, column, label_text, line_edit, unit_text=""):
        self._compact_line_edit(line_edit)
        layout.addWidget(self._new_field_label(label_text, 96), row, column)
        layout.addWidget(line_edit, row, column + 1)
        layout.addWidget(self._new_unit_label(unit_text), row, column + 2)

    def _hide_widgets(self, *names):
        for name in names:
            widget = getattr(self, name, None)
            if widget is not None:
                widget.hide()

    def _button_policy(self, button, minimum_height=38):
        button.setMinimumHeight(minimum_height)
        button.setSizePolicy(QtWidgets.QSizePolicy.Expanding, QtWidgets.QSizePolicy.Fixed)

    def _layout_parameter_page(self):
        self.graphicsView_pictureParameters.setMinimumWidth(220)
        self.graphicsView_pictureParameters.setMaximumWidth(360)
        self.graphicsView_pictureParameters.setSizePolicy(
            QtWidgets.QSizePolicy.Preferred,
            QtWidgets.QSizePolicy.Expanding,
        )
        self.graphicsView_pictureParameters.setHorizontalScrollBarPolicy(QtCore.Qt.ScrollBarAlwaysOff)
