    def _scaled_point_size(self, base_size, minimum=None, maximum=None):
        scale = getattr(self, "_ui_scale", 1.0)
        point_size = int(round(base_size * scale))
        if minimum is not None:
            point_size = max(minimum, point_size)
        if maximum is not None:
            point_size = min(maximum, point_size)
        return point_size

    def _set_widget_font(self, widget, base_size, bold=None, minimum=None, maximum=None):
        font = widget.font()
        font.setPointSize(self._scaled_point_size(base_size, minimum, maximum))
        if bold is not None:
            font.setBold(bold)
        widget.setFont(font)

    def _calculate_ui_scale(self):
        reference_width = 1360
        reference_height = 808
        width_ratio = max(0.1, self.width() / reference_width)
        height_ratio = max(0.1, self.height() / reference_height)
        ratio = min(width_ratio, height_ratio)
        scale = 1.0 + ((ratio - 1.0) * 0.38)
        return max(0.96, min(1.23, scale))

    def _apply_responsive_scale(self):
        if not hasattr(self, "_responsive_labels"):
            return

        scale = self._calculate_ui_scale()
        if getattr(self, "_ui_scale_applied", False) and abs(scale - getattr(self, "_ui_scale", 1.0)) < 0.015:
            return

        self._ui_scale = scale
        self._ui_scale_applied = True
        self._set_widget_font(self, 9, minimum=9, maximum=11)

        for label in self._responsive_labels:
            is_parameter_label = label.font().bold()
            self._set_widget_font(
                label,
                11 if is_parameter_label else 10,
                bold=is_parameter_label,
                minimum=10,
                maximum=14,
            )

        for group_box in self.findChildren(QtWidgets.QGroupBox):
            if group_box in (
                self.groupBox_3,
                self.groupBox_4,
                self.groupBox_5,
                self.groupBox_acknowledgements,
            ):
                self._set_widget_font(group_box, 15, bold=True, minimum=15, maximum=20)
            else:
                self._set_widget_font(group_box, 11, bold=True, minimum=11, maximum=14)

        for button in self.findChildren(QtWidgets.QAbstractButton):
            self._set_widget_font(button, 9, bold=True, minimum=9, maximum=12)

        parameter_fields = (
            self.lineEdit_H1, self.lineEdit_H2, self.lineEdit_d_T, self.lineEdit_d_R,
            self.lineEdit_alpha, self.lineEdit_beta, self.lineEdit_n, self.lineEdit_wavelength,
            self.lineEdit_r_Tx_min, self.lineEdit_r_Rx_min, self.lineEdit_t_slice,
            self.lineEdit_K, self.lineEdit_intLoss, self.lineEdit_importParameters,
            self.lineEdit_selectOutput, self.lineEdit_H1Value, self.lineEdit_H2Value,
            self.lineEdit_alphaValue, self.lineEdit_betaValue,
        )
        field_height = max(28, min(36, int(round(30 * scale))))
        for line_edit in parameter_fields:
            self._set_widget_font(line_edit, 10, minimum=10, maximum=13)
            line_edit.setMinimumHeight(field_height)

        button_height = max(38, min(48, int(round(40 * scale))))
        primary_height = max(42, min(54, int(round(44 * scale))))
        for button in (
            self.button_storeParameters,
            self.button_updateParameters,
            self.button_selectParametersFile,
            self.button_loadParameters,
            self.button_selectOutput,
            self.button_call_3D_plot,
        ):
            button.setMinimumHeight(button_height)
        self.button_runSimulation.setMinimumHeight(primary_height)
        self.button_stopSimulation.setMinimumHeight(primary_height)

        self.progressBar.setMinimumHeight(max(30, min(38, int(round(31 * scale)))))
        self.label1.setMinimumHeight(max(112, min(148, int(round(118 * scale)))))
        self._set_widget_font(self.label1, 10, bold=False, minimum=10, maximum=12)
        self._refresh_about_text()

    def _request_3d_plot_resize(self):
        plotly_view = getattr(self, "_plotly_view", None)
        if not getattr(self, "_plotly_ready", False) or plotly_view is None:
            return
        plotly_view.page().runJavaScript(
            "(function(){if(window.ISatQuLLoSPlot&&window.ISatQuLLoSPlot.resizePlot){window.ISatQuLLoSPlot.resizePlot();}})();"
        )

    def _plot_status_kind(self, text):
        lowered_text = text.lower()
        if "simulation" in lowered_text:
            return "simulation"
        if "custom" in lowered_text:
            return "custom"
        return "default"

