    def _close_3d_orbit_arrays(self, x, y, z):
        if len(x) < 2 or len(y) < 2 or len(z) < 2:
            return x, y, z

        first_point = np.array([x[0], y[0], z[0]], dtype=float)
        last_point = np.array([x[-1], y[-1], z[-1]], dtype=float)
        radius = max(float(np.linalg.norm(first_point)), 1.0)
        if np.linalg.norm(first_point - last_point) <= radius * 1e-5:
            return x, y, z

        return (
            np.append(x, x[0]),
            np.append(y, y[0]),
            np.append(z, z[0]),
        )

    def _downsample_3d_orbit_arrays(self, x1, y1, z1, x2, y2, z2):
        arrays = [
            np.asarray(values, dtype=float)
            for values in (x1, y1, z1, x2, y2, z2)
        ]
        sample_count = min(len(values) for values in arrays)
        if sample_count <= 0:
            return arrays

        arrays = [values[:sample_count] for values in arrays]
        max_samples = getattr(self, "_max_3d_orbit_samples", 360)
        if sample_count > max_samples:
            indices = np.linspace(0, sample_count - 1, max_samples, dtype=int)
            indices = np.unique(indices)
            arrays = [values[indices] for values in arrays]

        x1, y1, z1 = self._close_3d_orbit_arrays(arrays[0], arrays[1], arrays[2])
        x2, y2, z2 = self._close_3d_orbit_arrays(arrays[3], arrays[4], arrays[5])
        return [x1, y1, z1, x2, y2, z2]

    def _optimize_3d_orbit_traces(self, fig):
        if fig is None or len(fig.data) <= 5:
            return

        x1, y1, z1, x2, y2, z2 = self._downsample_3d_orbit_arrays(
            fig.data[1].x,
            fig.data[1].y,
            fig.data[1].z,
            fig.data[2].x,
            fig.data[2].y,
            fig.data[2].z,
        )
        fig.data[1].x = x1
        fig.data[1].y = y1
        fig.data[1].z = z1
        fig.data[2].x = x2
        fig.data[2].y = y2
        fig.data[2].z = z2
        fig.data[4].x = [x1[0]]
        fig.data[4].y = [y1[0]]
        fig.data[4].z = [z1[0]]
        fig.data[5].x = [x2[0]]
        fig.data[5].y = [y2[0]]
        fig.data[5].z = [z2[0]]

    def _plain_plotly_value(self, value):
        if isinstance(value, np.ndarray):
            return value.tolist()
        if isinstance(value, np.generic):
            return value.item()
        if isinstance(value, tuple):
            return [self._plain_plotly_value(item) for item in value]
        if isinstance(value, list):
            return [self._plain_plotly_value(item) for item in value]
        if isinstance(value, dict):
            return {
                key: self._plain_plotly_value(item)
                for key, item in value.items()
            }
        if hasattr(value, "to_plotly_json"):
            return self._plain_plotly_value(value.to_plotly_json())
        return value

    def _figure_payload_json(self, fig):
        layout_payload = self._plain_plotly_value(fig.layout.to_plotly_json())
        layout_payload.pop("template", None)
        payload = {
            "data": [],
            "layout": layout_payload,
        }
        for trace in fig.data:
            trace_payload = self._plain_plotly_value(trace.to_plotly_json())
            for coordinate_name in ("x", "y", "z", "surfacecolor"):
                coordinate_value = getattr(trace, coordinate_name, None)
                if coordinate_value is not None:
                    trace_payload[coordinate_name] = self._plain_plotly_value(coordinate_value)
            payload["data"].append(trace_payload)
        return json.dumps(payload, separators=(",", ":"))

    def _runtime_plotly_directory(self):
        runtime_dir = QtCore.QStandardPaths.writableLocation(QtCore.QStandardPaths.AppDataLocation)
        if not runtime_dir:
            runtime_dir = os.path.join(BASE_DIR, ".isatqullos_runtime")
        os.makedirs(runtime_dir, exist_ok=True)
        return runtime_dir

    def _plotly_javascript_source(self):
        plotly_js_path = os.path.join(self._runtime_plotly_directory(), "plotly.min.js")
        if not os.path.exists(plotly_js_path) or os.path.getsize(plotly_js_path) < 100000:
            with open(plotly_js_path, "w", encoding="utf-8") as file:
                file.write(plotly_offline.get_plotlyjs())
        return "plotly.min.js"

    def _build_plotly_html(self, fig):
        status_kind = self._plot_status_kind(self._plot_status_text)
        status_html = (
            f'<div id="plotStatus" class="{html.escape(status_kind)}">'
            f'<strong>{html.escape(self._plot_status_text)}</strong>'
            f'<span>{html.escape(self._plot_status_detail)}</span>'
            '</div>'
        )
        plotly_script = html.escape(self._plotly_javascript_source(), quote=True)
        return (
            "<!DOCTYPE html><html><head><meta charset=\"utf-8\">"
            f"<script charset=\"utf-8\" src=\"{plotly_script}\"></script>"
            "<style>"
            "html, body { width: 100%; height: 100%; margin: 0; overflow: hidden; background: #f8fafc; }"
            ".plotly-graph-div, .js-plotly-plot, .plot-container, .svg-container { width: 100vw !important; height: 100vh !important; }"
            ".modebar { right: 12px !important; top: 12px !important; }"
            ".modebar-group { padding-left: 4px !important; }"
            ".modebar-btn { width: 42px !important; height: 42px !important; }"
            ".modebar-btn svg { width: 25px !important; height: 25px !important; }"
            ".legend text, .legendtext { font-size: 18px !important; font-family: 'Segoe UI', Arial, sans-serif !important; }"
            "#orbitToggle { position: fixed; left: 22px; bottom: 22px; z-index: 50; width: 104px; height: 104px; border-radius: 50%; border: 1px solid rgba(255,255,255,0.72); background: rgba(16,47,74,0.88); box-shadow: 0 14px 34px rgba(16,47,74,0.28); display: flex; align-items: center; justify-content: center; cursor: pointer; outline: none; -webkit-tap-highlight-color: transparent; }"
            "#orbitToggle:focus, #orbitToggle:focus-visible { outline: none; box-shadow: 0 14px 34px rgba(16,47,74,0.28); }"
            "#orbitToggle:hover { background: rgba(24,78,119,0.94); }"
            "#orbitToggle:active { transform: translateY(1px); }"
            ".orbitIcon.play { margin-left: 8px; width: 0; height: 0; border-top: 24px solid transparent; border-bottom: 24px solid transparent; border-left: 38px solid #ffffff; }"
            ".orbitIcon.pause { position: relative; display: block; width: 58px; height: 50px; }"
            ".orbitIcon.pause:before, .orbitIcon.pause:after { content: ''; position: absolute; top: 0; display: block; width: 12px; height: 50px; border-radius: 4px; background: #ffffff; }"
            ".orbitIcon.pause:before { left: 9px; }"
            ".orbitIcon.pause:after { right: 9px; }"
            "#plotStatus { position: fixed; right: 18px; bottom: 18px; z-index: 45; min-width: 205px; max-width: 360px; border-radius: 10px; border: 1px solid rgba(148,163,184,0.52); background: rgba(255,255,255,0.86); box-shadow: 0 10px 24px rgba(16,47,74,0.14); color: #102f4a; font-family: 'Segoe UI', Arial, sans-serif; padding: 10px 13px; pointer-events: none; }"
            "#plotStatus strong { display: block; font-size: 14px; line-height: 1.2; }"
            "#plotStatus span { display: block; margin-top: 3px; color: #52677a; font-size: 12px; line-height: 1.2; }"
            "#plotStatus.default { border-color: rgba(47,128,237,0.35); }"
            "#plotStatus.custom { border-color: rgba(245,159,0,0.46); background: rgba(255,251,235,0.9); }"
            "#plotStatus.simulation { border-color: rgba(47,159,103,0.46); background: rgba(240,253,244,0.9); }"
            "</style></head><body>"
            "<div id=\"isatqullosPlot\" class=\"plotly-graph-div\" style=\"width:100vw;height:100vh;\"></div>"
            + status_html
            + "<button id=\"orbitToggle\" type=\"button\" title=\"Play orbit animation\" aria-label=\"Play orbit animation\"><span class=\"orbitIcon play\"></span></button>"
            + """
            <script>
            (function () {
                var state = {
                    timer: null,
                    index: 0,
                    intervalMs: 120,
                    userInteracting: false,
                    playing: false,
                    resumeTimer: null,
                    lastFrameTime: null,
                    figureReady: false,
                    pendingTracePayload: null,
                    earthSurfaceVisible: true
                };

                function plotDiv() {
                    return document.querySelector('.plotly-graph-div');
                }

                function cloneObject(value) {
                    if (!value) {
                        return null;
                    }
                    return JSON.parse(JSON.stringify(value));
                }

                function currentPlotCamera() {
                    var div = plotDiv();
                    if (div && div._fullLayout && div._fullLayout.scene && div._fullLayout.scene.camera) {
                        return cloneObject(div._fullLayout.scene.camera);
                    }
                    if (div && div.layout && div.layout.scene && div.layout.scene.camera) {
                        return cloneObject(div.layout.scene.camera);
                    }
                    return null;
                }

                function syncLayoutCamera() {
                    var div = plotDiv();
                    var camera = currentPlotCamera();
                    if (!div || !camera) {
                        return null;
                    }
                    div.layout = div.layout || {};
                    div.layout.scene = div.layout.scene || {};
                    div.layout.scene.camera = cloneObject(camera);
                    return camera;
                }

                function restyleTraces(update, traces, keepCamera) {
                    var div = plotDiv();
                    if (!window.Plotly || !div) {
                        return null;
                    }
                    if (keepCamera) {
                        syncLayoutCamera();
                    }
                    return Plotly.restyle(div, update, traces);
                }

                function traceValues(trace, axis) {
                    var values = trace && trace[axis];
                    if (!values) {
                        return [];
                    }
                    if (Array.isArray(values) || typeof values.length === 'number') {
                        return values;
                    }
                    return [];
                }

                function availableSamples(div) {
                    if (!div || !div.data || !div.data[1] || !div.data[2]) {
                        return 0;
                    }
                    return Math.min(
                        traceValues(div.data[1], 'x').length,
                        traceValues(div.data[1], 'y').length,
                        traceValues(div.data[1], 'z').length,
                        traceValues(div.data[2], 'x').length,
                        traceValues(div.data[2], 'y').length,
                        traceValues(div.data[2], 'z').length
                    );
                }

                function moveMarkers(index) {
                    var div = plotDiv();
                    if (!window.Plotly || !div || !div.data || !div.data[1] || !div.data[2]) {
                        return;
                    }
                    var count = availableSamples(div);
                    if (count < 1) {
                        return;
                    }
                    var i = ((index % count) + count) % count;
                    state.index = i;
                    var orbit1 = div.data[1];
                    var orbit2 = div.data[2];
                    var x1 = traceValues(orbit1, 'x');
                    var y1 = traceValues(orbit1, 'y');
                    var z1 = traceValues(orbit1, 'z');
                    var x2 = traceValues(orbit2, 'x');
                    var y2 = traceValues(orbit2, 'y');
                    var z2 = traceValues(orbit2, 'z');
                    return restyleTraces({
                        x: [[x1[i]], [x2[i]]],
                        y: [[y1[i]], [y2[i]]],
                        z: [[z1[i]], [z2[i]]]
                    }, [4, 5]);
                }

                function styleSatelliteMarkers() {
                    var div = plotDiv();
                    if (!window.Plotly || !div) {
                        return;
                    }
                    restyleTraces({
                        mode: ['markers', 'markers'],
                        visible: [true, true],
                        'marker.color': ['#1d4ed8', '#f08c00'],
                        'marker.size': [10, 10],
                        'marker.opacity': [1, 1],
                        'marker.symbol': ['circle', 'circle'],
                        'marker.line.color': ['#0f2d63', '#a35200'],
                        'marker.line.width': [1, 1]
                    }, [4, 5], true);
                }

                function stepAnimation() {
                    var div = plotDiv();
                    var count = availableSamples(div);
                    if (count < 2) {
                        return;
                    }
                    return moveMarkers((state.index + 1) % count);
                }

                function stopAnimation() {
                    if (state.timer) {
                        window.clearTimeout(state.timer);
                        state.timer = null;
                    }
                }

                function scheduleAnimationTick(delayMs) {
                    stopAnimation();
                    if (!state.playing) {
                        return;
                    }
                    state.timer = window.setTimeout(function () {
                        if (!state.playing) {
                            return;
                        }
                        state.timer = null;
                        stepAnimation();
                        if (state.playing) {
                            scheduleAnimationTick(state.intervalMs);
                        }
                    }, delayMs || state.intervalMs);
                }

                function startAnimation(delayMs) {
                    if (state.userInteracting || !state.playing) {
                        return;
                    }
                    scheduleAnimationTick(delayMs || state.intervalMs);
                }

                function updateToggleButton() {
                    var button = document.getElementById('orbitToggle');
                    if (!button) {
                        return;
                    }
                    var label = state.playing ? 'Pause orbit animation' : 'Play orbit animation';
                    button.title = label;
                    button.setAttribute('aria-label', label);
                    button.innerHTML = state.playing
                        ? '<span class="orbitIcon pause"></span>'
                        : '<span class="orbitIcon play"></span>';
                }

                function setAnimationPlaying(playing) {
                    state.playing = !!playing;
                    state.userInteracting = false;
                    if (state.resumeTimer) {
                        window.clearTimeout(state.resumeTimer);
                        state.resumeTimer = null;
                    }
                    if (state.playing) {
                        stopAnimation();
                        syncLayoutCamera();
                        state.lastFrameTime = null;
                        updateToggleButton();
                        startAnimation(140);
                    } else {
                        stopAnimation();
                        state.lastFrameTime = null;
                        updateToggleButton();
                    }
                }

                function toggleAnimation() {
                    setAnimationPlaying(!state.playing);
                }

                function resumeAnimationSoon(delayMs) {
                    if (state.resumeTimer) {
                        window.clearTimeout(state.resumeTimer);
                    }
                    state.resumeTimer = window.setTimeout(function () {
                        state.userInteracting = false;
                        startAnimation();
                    }, delayMs || 900);
                }

                function pauseForInteraction(autoResumeDelay) {
                    state.userInteracting = false;
                    if (state.resumeTimer) {
                        window.clearTimeout(state.resumeTimer);
                        state.resumeTimer = null;
                    }
                }

                function resizeStatusBadge() {
                    var badge = document.getElementById('plotStatus');
                    if (!badge) {
                        return;
                    }
                    var shortSide = Math.min(window.innerWidth || 0, window.innerHeight || 0);
                    var scale = Math.max(0.98, Math.min(1.35, 0.92 + (shortSide / 1500)));
                    badge.style.padding = Math.round(10 * scale) + 'px ' + Math.round(13 * scale) + 'px';
                    badge.style.borderRadius = Math.round(10 * scale) + 'px';
                    badge.style.minWidth = Math.round(205 * scale) + 'px';
                    badge.style.maxWidth = Math.round(360 * scale) + 'px';
                    var title = badge.querySelector('strong');
                    var detail = badge.querySelector('span');
                    if (title) {
                        title.style.fontSize = Math.round(14 * scale) + 'px';
                    }
                    if (detail) {
                        detail.style.fontSize = Math.round(12 * scale) + 'px';
                    }
                }

                function resizePlot() {
                    var div = plotDiv();
                    resizeStatusBadge();
                    if (window.Plotly && div) {
                        div.style.width = window.innerWidth + 'px';
                        div.style.height = window.innerHeight + 'px';
                        Plotly.relayout(div, {
                            width: window.innerWidth,
                            height: window.innerHeight,
                            autosize: true
                        });
                        Plotly.Plots.resize(div);
                    }
                }

                function updateOrbitTraces(payload) {
                    var div = plotDiv();
                    if (!window.Plotly || !div || !payload) {
                        return false;
                    }
                    if (!state.figureReady) {
                        state.pendingTracePayload = payload;
                        return false;
                    }

                    var x1 = payload.x1 || [];
                    var y1 = payload.y1 || [];
                    var z1 = payload.z1 || [];
                    var x2 = payload.x2 || [];
                    var y2 = payload.y2 || [];
                    var z2 = payload.z2 || [];
                    if (!x1.length || !x2.length) {
                        return false;
                    }

                    stopAnimation();
                    restyleTraces({
                        x: [x1, x2],
                        y: [y1, y2],
                        z: [z1, z2]
                    }, [1, 2], true);
                    restyleTraces({
                        x: [[x1[0]], [x2[0]]],
                        y: [[y1[0]], [y2[0]]],
                        z: [[z1[0]], [z2[0]]]
                    }, [4, 5], true);
                    state.index = 0;
                    state.lastFrameTime = null;
                    if (state.playing) {
                        startAnimation();
                    }
                    return true;
                }

                function setPlotStatus(text, detail, kind) {
                    var badge = document.getElementById('plotStatus');
                    if (!badge) {
                        return;
                    }
                    badge.className = kind || '';
                    badge.innerHTML = '<strong></strong><span></span>';
                    badge.querySelector('strong').textContent = text || 'Plot status';
                    badge.querySelector('span').textContent = detail || '';
                    resizeStatusBadge();
                }

                function updateFigure(payload) {
                    var div = plotDiv();
                    if (!window.Plotly || !div || !payload) {
                        return false;
                    }

                    var layout = payload.layout || {};
                    layout.uirevision = 'isatqullos-live-camera';

                    stopAnimation();
                    state.figureReady = false;
                    var update = Plotly.react(div, payload.data, layout, {
                        responsive: true,
                        displaylogo: false,
                        scrollZoom: true
                    });
                    var afterUpdate = function () {
                        state.figureReady = true;
                        state.earthSurfaceVisible = true;
                        window.ISatQuLLoSPlotLoaded = true;
                        bindPlotInteractionHandlers();
                        styleSatelliteMarkers();
                        moveMarkers(0);
                        if (state.pendingTracePayload) {
                            var pendingTracePayload = state.pendingTracePayload;
                            state.pendingTracePayload = null;
                            updateOrbitTraces(pendingTracePayload);
                        }
                        if (state.playing) {
                            startAnimation();
                        }
                        resizePlot();
                    };
                    if (update && update.then) {
                        update.then(afterUpdate);
                    } else {
                        afterUpdate();
                    }
                    return true;
                }

                function bindPlotInteractionHandlers() {
                    var div = plotDiv();
                    if (!div || div.__isatqullosInteractionBound) {
                        return;
                    }
                    div.__isatqullosInteractionBound = true;
                    if (window.Plotly && div.on) {
                        div.on('plotly_legendclick', function (eventData) {
                            if (!eventData || !div.data || !div.data[0]) {
                                return true;
                            }
                            var curveNumber = eventData.curveNumber;
                            var trace = div.data[curveNumber];
                            if (!trace || trace.name !== 'Earth surface' || curveNumber === 0) {
                                return true;
                            }
                            state.earthSurfaceVisible = !state.earthSurfaceVisible;
                            syncLayoutCamera();
                            Plotly.restyle(div, { opacity: state.earthSurfaceVisible ? 0.34 : 0 }, [0]);
                            Plotly.restyle(div, { visible: state.earthSurfaceVisible ? true : 'legendonly' }, [curveNumber]);
                            return false;
                        });
                    }
                }

                function bindToggleButton() {
                    var button = document.getElementById('orbitToggle');
                    if (!button || button.__isatqullosBound) {
                        return;
                    }
                    button.__isatqullosBound = true;
                    button.addEventListener('click', function (event) {
                        event.preventDefault();
                        event.stopPropagation();
                        button.blur();
                        toggleAnimation();
                    });
                    updateToggleButton();
                }

                window.ISatQuLLoSPlot = {
                    updateFigure: updateFigure,
                    updateOrbitTraces: updateOrbitTraces,
                    isReady: function () { return !!state.figureReady; },
                    startAnimation: startAnimation,
                    stopAnimation: stopAnimation,
                    setAnimationPlaying: setAnimationPlaying,
                    setPlotStatus: setPlotStatus,
                    resizePlot: resizePlot
                };

                function initializeSceneWhenReady(attempt) {
                    attempt = attempt || 0;
                    var div = plotDiv();
                    if (!window.Plotly || !div || !div.data || !div.data[1] || !div.data[2] || !div._fullLayout) {
                        if (attempt < 40) {
                            window.setTimeout(function () {
                                initializeSceneWhenReady(attempt + 1);
                            }, 150);
                        }
                        return;
                    }

                    bindPlotInteractionHandlers();
                    bindToggleButton();
                    styleSatelliteMarkers();
                    moveMarkers(state.index || 0);
                    setAnimationPlaying(false);
                    resizePlot();
                    window.setTimeout(function () {
                        styleSatelliteMarkers();
                        moveMarkers(state.index || 0);
                        resizePlot();
                    }, 300);
                }

                document.addEventListener('visibilitychange', function () {
                    if (document.hidden) {
                        stopAnimation();
                    } else if (state.playing) {
                        startAnimation();
                    }
                });
                window.addEventListener('resize', resizePlot);
                window.setTimeout(function () {
                    initializeSceneWhenReady(0);
                }, 250);
            }());
            </script>
            </body></html>
            """
        )

    def _ensure_3d_plot_view(self):
        if self._plotly_view is not None:
            return self._plotly_view

        if self.views:
            view = self.views[0]
        else:
            view = QWebEngineView()
            self.views.append(view)

        self._plotly_view = view
        view.setZoomFactor(1.0)
        view.setMinimumSize(0, 0)
        view.setSizePolicy(
            QtWidgets.QSizePolicy.Expanding,
            QtWidgets.QSizePolicy.Expanding,
        )

        if not self._plotly_load_connected:
            view.loadFinished.connect(self._on_3d_plot_load_finished)
            self._plotly_load_connected = True

        layout = self.openGLWidget_3Dplot.layout()
        if layout is None:
            layout = QtWidgets.QVBoxLayout(self.openGLWidget_3Dplot)
            layout.setContentsMargins(0, 0, 0, 0)
            layout.setSpacing(0)

        if view.parent() is None:
            layout.addWidget(view)

        for extra_view in self.views[1:]:
            extra_view.setParent(None)

        return view

    def _on_3d_plot_load_finished(self, ok):
        if not ok:
            self._plotly_ready = False
            self._plotly_html_loaded = False
            return

        self._plotly_ready = False
        self._schedule_3d_payload_flush()

    def _schedule_3d_payload_flush(self):
        if (
            self._plotly_view is None
            or (
                self._pending_3d_payload_json is None
                and self._pending_3d_trace_payload_json is None
            )
        ):
            return
        if self._plotly_flush_scheduled:
            return
        if self._plotly_retry_count >= 80:
            return

        self._plotly_flush_scheduled = True
        self._plotly_retry_count += 1
        QTimer.singleShot(250, self._flush_pending_3d_payload)

    def _flush_pending_3d_payload(self):
        self._plotly_flush_scheduled = False
        if (
            self._plotly_view is None
            or (
                self._pending_3d_payload_json is None
                and self._pending_3d_trace_payload_json is None
            )
        ):
            return

        script = (
            "(function(){return !!("
            "window.ISatQuLLoSPlot&&window.ISatQuLLoSPlot.updateFigure&&window.ISatQuLLoSPlot.updateOrbitTraces"
            ");})();"
        )
        self._plotly_view.page().runJavaScript(script, self._finish_3d_payload_flush)

    def _finish_3d_payload_flush(self, js_ready):
        if (
            self._plotly_view is None
            or (
                self._pending_3d_payload_json is None
                and self._pending_3d_trace_payload_json is None
            )
        ):
            return

        if js_ready:
            payload_json = self._pending_3d_payload_json
            trace_payload_json = self._pending_3d_trace_payload_json
            self._pending_3d_payload_json = None
            self._pending_3d_trace_payload_json = None
            self._plotly_retry_count = 0
            self._plotly_ready = True
            if payload_json is not None:
                self._push_3d_payload(payload_json)
            if trace_payload_json is not None:
                QTimer.singleShot(
                    350,
                    lambda payload=trace_payload_json: self._push_3d_trace_payload(payload),
                )
            self._push_3d_plot_status()
            return

        self._plotly_ready = False
        self._schedule_3d_payload_flush()

    def _push_3d_payload(self, payload_json):
        if self._plotly_view is None:
            return
        self._plotly_ready = True
        script = (
            "(function(){"
            "if(window.ISatQuLLoSPlot&&window.ISatQuLLoSPlot.updateFigure){"
            "window.ISatQuLLoSPlot.updateFigure("
            + payload_json +
            ");}})();"
        )
        self._plotly_view.page().runJavaScript(script)

    def _push_3d_trace_payload(self, payload_json):
        if self._plotly_view is None:
            return
        self._plotly_ready = True
        script = (
            "(function(){"
            "if(window.ISatQuLLoSPlot&&window.ISatQuLLoSPlot.updateOrbitTraces){"
            "window.ISatQuLLoSPlot.updateOrbitTraces("
            + payload_json +
            ");}})();"
        )
        self._plotly_view.page().runJavaScript(script)

    def _push_3d_plot_status(self):
        if self._plotly_view is None:
            return
        text_json = json.dumps(self._plot_status_text)
        detail_json = json.dumps(self._plot_status_detail)
        kind_json = json.dumps(self._plot_status_kind(self._plot_status_text))
        script = (
            "(function(){"
            "if(window.ISatQuLLoSPlot&&window.ISatQuLLoSPlot.setPlotStatus){"
            "window.ISatQuLLoSPlot.setPlotStatus("
            + text_json + "," + detail_json + "," + kind_json +
            ");}})();"
        )
        self._plotly_view.page().runJavaScript(script)

    def _queue_3d_trace_payload(self, payload_json):
        if not self._plotly_ready:
            self._pending_3d_trace_payload_json = payload_json
            self._schedule_3d_payload_flush()
            return

        self._push_3d_trace_payload(payload_json)

    def _update_3d_orbit_traces(self, x1, y1, z1, x2, y2, z2):
        self._update_3d_orbit_traces_km(
            x1 * 10 ** (-3),
            y1 * 10 ** (-3),
            z1 * 10 ** (-3),
            x2 * 10 ** (-3),
            y2 * 10 ** (-3),
            z2 * 10 ** (-3),
        )

    def _update_3d_orbit_traces_km(self, x1, y1, z1, x2, y2, z2):
        x1, y1, z1, x2, y2, z2 = self._downsample_3d_orbit_arrays(
            x1, y1, z1, x2, y2, z2
        )
        payload = {
            "x1": x1.tolist(),
            "y1": y1.tolist(),
            "z1": z1.tolist(),
            "x2": x2.tolist(),
            "y2": y2.tolist(),
            "z2": z2.tolist(),
        }
        self._queue_3d_trace_payload(json.dumps(payload, separators=(",", ":")))

    def display_3D_plot_trace_update(self, fig, status_text=None, status_detail=""):
        if fig is None or len(fig.data) <= 5:
            self.display_3D_plot(fig, status_text, status_detail)
            return

        if status_text is not None:
            self._plot_status_text = status_text
            self._plot_status_detail = status_detail

        self.fig3D = fig
        self._polish_3d_figure(fig)
        self._optimize_3d_orbit_traces(fig)

        if not self._plotly_html_loaded:
            self.display_3D_plot(fig, status_text, status_detail)
            return

        self._update_3d_orbit_traces_km(
            fig.data[1].x,
            fig.data[1].y,
            fig.data[1].z,
            fig.data[2].x,
            fig.data[2].y,
            fig.data[2].z,
        )
        self._push_3d_plot_status()

    #Method to display the 3D plot in the openGLWidget_3Dplot widget
    def display_3D_plot(self, fig, status_text=None, status_detail=""):
        if status_text is not None:
            self._plot_status_text = status_text
            self._plot_status_detail = status_detail

        self.fig3D = fig
        self._polish_3d_figure(fig)
        self._optimize_3d_orbit_traces(fig)
        view = self._ensure_3d_plot_view()
        payload_json = self._figure_payload_json(fig)

        if not self._plotly_html_loaded:
            self._plotly_ready = False
            self._plotly_html_loaded = True
            self._pending_3d_payload_json = payload_json
            html_path = os.path.join(self._runtime_plotly_directory(), "temp.html")
            with open(html_path, "w", encoding="utf-8") as file:
                file.write(self._build_plotly_html(fig))
            view.setUrl(QUrl.fromLocalFile(html_path.replace("\\", "/")))
            self._schedule_3d_payload_flush()
            return

        if not self._plotly_ready:
            self._pending_3d_payload_json = payload_json
            self._schedule_3d_payload_flush()
            return

        self._push_3d_payload(payload_json)
        self._push_3d_plot_status()

    #Method to display the matplotlib 2D interactive diagrams.
    def display_figure_in_QGraphicsView(self, fig, graphics_view_name):
        # Create a QWidget as a placeholder for the FigureCanvas
        plot_widget = QtWidgets.QWidget()

        # Create a FigureCanvas widget and set the Figure as its parent
        canvas = FigureCanvas(fig)
        canvas.setParent(plot_widget)

        # Create a NavigationToolbar
        toolbar = NavigationToolbar(canvas, plot_widget)

        # Create a QVBoxLayout to hold the FigureCanvas and NavigationToolbar
        layout = QtWidgets.QVBoxLayout(plot_widget)
        layout.addWidget(canvas)
        layout.addWidget(toolbar)

        # Get a reference to the QGraphicsView widget
        graphics_view = getattr(self, graphics_view_name)

        # Set the QWidget as the viewport of the QGraphicsView
        graphics_view.setViewport(plot_widget)
        canvas.draw()

    #Method to display the printed statements from the simulations onto the GUI.
    def append_text(self, text):
        cursor = self.textEdit_output.textCursor()
        cursor.movePosition(QtGui.QTextCursor.End)
        cursor.insertText(text)
        self.textEdit_output.setTextCursor(cursor)
        self.textEdit_output.ensureCursorVisible()

    @QtCore.pyqtSlot(int)
    def update_progress_bar(self, progress):
        #This sets the value of the progress bar.
        progress = max(0, min(100, int(progress)))
        self.progressBar.setValue(progress)
        QtWidgets.QApplication.processEvents() #This fixes the interface freeze when running the simulations.


